import React from "react";
import { MapContainer, TileLayer, Marker, Popup, useMapEvents } from "react-leaflet";

function DestinationMarker({ setFinalLocation }) {

  useMapEvents({

    click(e) {

      setFinalLocation([e.latlng.lat, e.latlng.lng]);

    }

  });

  return null;

}

function Map({ currentLocation, finalLocation, setFinalLocation }) {

  return (

    <MapContainer
      center={currentLocation || [25.5941, 85.1376]}
      zoom={13}
      style={{ height: "400px", width: "100%", marginTop: "30px" }}
    >

      <TileLayer
        url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
      />

      <DestinationMarker setFinalLocation={setFinalLocation} />

      {currentLocation && (

        <Marker position={currentLocation}>
          <Popup>Current Location</Popup>
        </Marker>

      )}

      {finalLocation && (

        <Marker position={finalLocation}>
          <Popup>Final Destination</Popup>
        </Marker>

      )}

    </MapContainer>

  )

}

export default Map
